<div class="pt">
<svg viewBox="0 0 700 380" xmlns="http://www.w3.org/2000/svg" style="width:100%;height:auto;background:#111113;border-radius:12px;border:1px solid rgba(255,255,255,.08);margin:20px 0">
  <text x="20" y="26" fill="#fafafa" font-size="16" font-weight="700" font-family="sans-serif">Um Plano Funciona Como Encerrar a Operação</text>
  <text x="20" y="44" fill="#a1a1aa" font-size="13" font-family="sans-serif">Esquema do padrão experimental de Masicampo &amp; Baumeister (2011)</text>
  <text x="350" y="58" fill="#a1a1aa" font-size="13" text-anchor="middle" font-family="sans-serif">Estatisticamente indistinguível do grupo que concluiu</text>
  <line x1="120" y1="70" x2="580" y2="70" stroke="rgba(255,255,255,.25)" stroke-dasharray="4,4"/>
  <line x1="120" y1="70" x2="120" y2="78" stroke="rgba(255,255,255,.25)"/>
  <line x1="580" y1="70" x2="580" y2="78" stroke="rgba(255,255,255,.25)"/>
